import { useState, useEffect } from 'react';
import api from '../../services/api';
import toast from 'react-hot-toast';

export default function VentaForm() {
  const [productos, setProductos] = useState([]);
  const [clienteNombre, setClienteNombre] = useState('');
  const [clienteDocumento, setClienteDocumento] = useState('');
  const [items, setItems] = useState([]);
  const [currentProducto, setCurrentProducto] = useState('');
  const [cantidad, setCantidad] = useState(1);

  useEffect(() => {
    const fetchProductos = async () => {
      try {
        const res = await api.get('/productos');
        setProductos(res.data);
      } catch (error) {
        toast.error('Error al cargar productos');
      }
    };
    fetchProductos();
  }, []);

  const addItem = () => {
    if (!currentProducto || cantidad <= 0) return;
    const producto = productos.find(p => p.id === parseInt(currentProducto));
    if (!producto) return;
    if (producto.stock_actual < cantidad) {
      toast.error(`Stock insuficiente de ${producto.nombre}. Disponible: ${producto.stock_actual}`);
      return;
    }
    setItems([...items, {
      producto_id: producto.id,
      producto_nombre: producto.nombre,
      cantidad: parseInt(cantidad),
      precio_unitario: producto.precio_venta
    }]);
    setCurrentProducto('');
    setCantidad(1);
  };

  const removeItem = (index) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!clienteNombre || items.length === 0) {
      toast.error('Complete nombre del cliente y al menos un producto');
      return;
    }
    try {
      await api.post('/ventas', {
        cliente_nombre: clienteNombre,
        cliente_documento: clienteDocumento,
        items: items.map(i => ({
          producto_id: i.producto_id,
          cantidad: i.cantidad
        }))
      });
      toast.success('Venta registrada exitosamente');
      setClienteNombre('');
      setClienteDocumento('');
      setItems([]);
    } catch (error) {
      toast.error(error.response?.data?.error || 'Error al registrar venta');
    }
  };

  const total = items.reduce((sum, i) => sum + (i.cantidad * i.precio_unitario), 0);

  return (
    <div>
      <h1 className="text-2xl font-bold mb-4">Registrar Venta</h1>
      <form onSubmit={handleSubmit} className="bg-white p-4 rounded shadow">
        <div className="mb-4">
          <label className="block text-sm font-medium">Nombre del cliente *</label>
          <input type="text" value={clienteNombre} onChange={e => setClienteNombre(e.target.value)} required className="w-full border p-2 rounded" />
        </div>
        <div className="mb-4">
          <label className="block text-sm font-medium">Documento (opcional)</label>
          <input type="text" value={clienteDocumento} onChange={e => setClienteDocumento(e.target.value)} className="w-full border p-2 rounded" />
        </div>
        <div className="border-t pt-4 mt-2">
          <h3 className="font-semibold mb-2">Agregar Producto</h3>
          <div className="grid grid-cols-3 gap-2">
            <select value={currentProducto} onChange={e => setCurrentProducto(e.target.value)} className="border p-2 rounded">
              <option value="">Seleccione producto</option>
              {productos.map(p => <option key={p.id} value={p.id}>{p.nombre} (Stock: {p.stock_actual})</option>)}
            </select>
            <input type="number" placeholder="Cantidad" value={cantidad} onChange={e => setCantidad(e.target.value)} className="border p-2 rounded" />
            <button type="button" onClick={addItem} className="bg-blue-500 text-white px-3 py-1 rounded">Agregar</button>
          </div>
        </div>
        {items.length > 0 && (
          <div className="mt-4">
            <h3 className="font-semibold">Productos vendidos</h3>
            <ul className="list-disc pl-5">
              {items.map((item, idx) => (
                <li key={idx}>
                  {item.producto_nombre} - {item.cantidad} x ${item.precio_unitario} = ${item.cantidad * item.precio_unitario}
                  <button type="button" onClick={() => removeItem(idx)} className="text-red-600 ml-2">Eliminar</button>
                </li>
              ))}
            </ul>
            <p className="font-bold mt-2">Total: ${total}</p>
          </div>
        )}
        <button type="submit" className="mt-4 bg-green-600 text-white px-4 py-2 rounded">Registrar Venta</button>
      </form>
    </div>
  );
}
